var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"확실해! 여기서 소리가 들렸어!","JPN":"間違いない！　ここから音が聞こえた！","ENG":"I'm sure of it! I heard something here!","TWN":"確定了！是那裡傳來的聲音！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"얼마 못 갔을 거야. 어서 쫓아!!","JPN":"そんなに遠くには行っていないはず、追うぞ！","ENG":"They're probably nearby. Get them!","TWN":"她們跑不遠的。快追！！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…갔죠?","JPN":"……もういなくなったでしょうか？","ENG":"...Are they gone?","TWN":"……走了嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응. 발소리도 멀어졌다.","JPN":"うん。足音も聞こえなくなった。","ENG":"Yes. Their footsteps sound distant.","TWN":"嗯，腳步聲已經走遠了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"내 말 대로 문 활짝 열어 두길 잘했지?","JPN":"やっぱりドアを開けておいてよかったでしょ？","ENG":"See? I told you leaving the door open was better.","TWN":"聽我的把門打開是對的吧？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그러게요. 설명만 들었을 때는 긴가민가했는데.","JPN":"はい、口で説明されたときは、ピンときませんでしたが。","ENG":"Yeah. I was unsure about it when you pitched it, but I can see now.","TWN":"是啊。光聽解釋的時候還是半信半疑的。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"홀로그램을 이용한 눈속임이라니. 미래전략실 실장직은 괜히 단 게 아닌가 봐요.","JPN":"ホログラムを使ったフェイクだなんて、未来戦略室の室長はさすがだなと思いましたね。","ENG":"Creating an illusion using holograms was a good idea. I guess you're the chief of the Future Strategy Department for a reason.","TWN":"利用全息圖使出的障眼法，看來你未來戰略室室長的位子不是白當的嘛。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"별거 아니야. 빛의 파장보다 작은 메타물질만 있으면 인식을 쉽게 왜곡시킬 수 있거든.","JPN":"大したことじゃないよ。光の波長より粒の小さいメタ物質があれば、視界を歪めることは簡単だもの。","ENG":"It's nothing. It's easy to distort sight with metamaterial that's smaller than the wavelengths of light.","TWN":"哼哼，這沒什麼大不了的。只要有比光的波長更小的超材料，就能輕易扭曲視線。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"인공구조를 주기적으로 배치해 물질 간의 상호작용을 제어하면, 표면 플라즈몬을 이용해 음의 굴절률을 유발할 수 있어.","JPN":"人工構造を周期的に配置し物質間の相互作用を制御すれば、表面プラズマを利用して音の屈折を誘発することができるの。","ENG":"You can use surface plasmons to cause negative-index refractions by placing artificial structures at regular intervals and controlling the interaction between matter.","TWN":"如果以規則的間隔佈置人造結構來控制物質間的相互作用，就可以透過表面等離子體形成負折射率……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"설명해 줘도 모르니 됐어요.","JPN":"説明を聞いてもよくわからないので、もう大丈夫ですよ。","ENG":"You don't need to explain it, I won't understand anyway.","TWN":"就算解釋了我也不會懂，還是算了吧……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"근처에 사람도 없으니, 이틈에 어서 옌 씨에게 연락하자고요.","JPN":"周りに人もいないようですし、今のうちにイェンさんに連絡しておきましょう。","ENG":"Since they're all gone, let's contact Yen while we can.","TWN":"周圍也沒人，快趁這個時候聯絡嫣杏吧？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……과연.","JPN":"……なるほど。","ENG":"...I see.","TWN":"……果然。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그럴 의도야 없겠지만 이노베이션이 나서다니. 상황이 꼬일 대로 꼬였군요.","JPN":"計画されたものではないでしょうけど、結果的にイノベーションが出てくる展開になるなんて。かなり複雑な状況のようですね。","ENG":"I didn't expect Innovation to intervene. The situation has gotten out of hand.","TWN":"這並非我的本意，沒想到改革的人會出手，情況變得有點複雜。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"정말로요. 이래도 되나 싶을 정도로 섬에 사람이 넘친다고요.","JPN":"そうなんです。信じられないくらい島に人がたくさん来ています。","ENG":"Seriously. There are so many people on this island, it's ridiculous.","TWN":"真的，島上的人多到有點誇張。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제 불찰입니다. 관리국 수배령으로 인해 블루로즈 섬의 한시적 개방이 허용됐거든요.","JPN":"これは私の不始末です。管理局の指名手配によって、ブルーローズ島が一時的に立ち入り可能になったんです。","ENG":"That was an oversight on my part. Blue Rose Island is temporarily open due to the Administration announcing the wanted criminals.","TWN":"是我的失誤。由於管理局的通緝令，藍玫瑰島暫時對外開放了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"소문을 듣고 용병이나 해적들까지 몰려온 탓에, 저희 측에서도 대처가 느려지고 있습니다.","JPN":"それを聞きつけた傭兵や海賊たちが一気に押し寄せてきているので、こちらの対応が間に合っていません。","ENG":"We are slow to act due to the mercenaries and pirates who swarmed in after hearing the news.","TWN":"因為聽到傳聞，連雇傭兵和海盜都湧了過來，我們這邊的應對也變得遲緩了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"해적들이야 둘째 치고, 고작 탈옥수 하나에 이렇게까지 할 필요가 있나요?","JPN":"海賊はともかく、脱獄犯一人のために、どうしてここまでするんですか？","ENG":"Pirates aside, is this really necessary for just one escaped convict?","TWN":"海盜暫且不說，至於為了一個逃犯做到這種地步嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"하다하다 제가 고등급 카운터인 것도 아니잖아요.","JPN":"私がハイランクのカウンターなら、まだ納得できますが……","ENG":"It's not like I'm a high-grade Counter.","TWN":"說到底，我也不是高級制裁者啊。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"휴양지에 연루된 유명인사들이 많은 만큼 문제를 빠르게 해결하고 싶어하는 이가 많습니다.","JPN":"リゾート地の件には、様々な著名人も関わっているので、みんなできるだけ早くこの問題を収束させたいのですよ。","ENG":"Many are hoping that this issue is resolved quickly, as there are multiple public figures involved with that vacation location.","TWN":"由於涉及到許多度假的名人，很多人都希望能迅速解決問題。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"세간에 화제인 상자도둑에… 유피 양도 이노베이션에 정규 태스크포스까지 얽혀 있으니까요.","JPN":"今話題となっている箱泥棒事件……それにユピさん自身もイノベーションと正規タスクフォースとは関わりがあるわけですから。","ENG":"There's the famous chest thief... And Yuppie, you are entangled with Innovation and an official TASKFORCE.","TWN":"這件事還涉及到引起轟動的寶箱竊賊……並且悠菲，你跟阿爾法崔克斯改革，還有科芬這個正規的特遣勢力公司都有瓜葛。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"관리국 입장에서는 제법 거물로 보였을 겁니다.","JPN":"管理局からすると、かなりの重要人物に見えたのでしょう。","ENG":"The Administration would've deemed you a big deal.","TWN":"在管理局看來，你應該是個大人物。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"백수 다음에는 해적. 해적 다음에는 범죄자.","JPN":"ニートの次は海賊、海賊の次は犯罪者。","ENG":"First, I was an unemployed bum. And then a pirate. And then a criminal.","TWN":"無業遊民之後是海盜，海盜之後是罪犯。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"하다하다 이제는 뒷세계의 거물이라니. 저도 모르는 사이에 출세했네요.","JPN":"そして最後は、裏社会の主要人物だなんて。　自分でも気づかないうちに、私ってば大物になっていたようですね。","ENG":"And now I'm a big shot of the underworld. Amazing how things turn out.","TWN":"現在竟然還成了黑道大佬，不知不覺中我也出頭了呢。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이상해.","JPN":"こんなの変だよ。","ENG":"This is all weird.","TWN":"但是奇怪……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"다 같이 보물을 찾으면 분명 즐거울 텐데… 왜 서로 싸우기만 하는 거야?","JPN":"みんなでする宝探しは楽しいことなのに……どうして喧嘩ばかりするの？","ENG":"It would be fun if we were all on the same team and looked for the treasure together... Why are we just fighting each other?","TWN":"一起找寶藏是件開心的事情……為什麼大家總是要互相爭鬥呢？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이런 건 전혀 즐겁지 않아.","JPN":"こんなのちっとも楽しくない。","ENG":"This is not fun at all.","TWN":"這種事一點都不開心。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"사리사욕에 눈 먼 이는 귀 또한 닫는 법이죠.","JPN":"欲望に頭を支配されると、周りが見えなくなるものです。","ENG":"Those who are blinded by greed do not listen to reason.","TWN":"被私欲蒙蔽的人，耳朵也會閉塞。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};